struct LFG_KV {
    LFG_KV(lfg_arch_enum arch, const char * suffix = nullptr);

    lfg_arch_enum arch;
    const char * suffix;

    std::string operator()(lfg_kv_enum kv) const;
};

// helper to handle gguf constants
// usage:
//
//   const auto tn = LFG_TN(LFG_ARCH_LIQUID);
//
//   std::string name = tn(LFG_TENSOR_OUTPUT);                     -> "output"
//   std::string name = tn(LFG_TENSOR_TOKEN_EMBD, "bias");         -> "token_embd.bias"
//   std::string name = tn(LFG_TENSOR_ATTN_NORM, "weight", 3);     -> "blk.3.attn_norm.weight"
//
struct LFG_TN_IMPL {
    const lfg_arch_enum arch;
    const lfg_tensor_enum tensor;
    const char * const suffix;
    const int bid;
    const int xid;

    const std::set<lfg_tensor_enum> model_tensors;

    LFG_TN_IMPL(lfg_arch_enum arch, lfg_tensor_enum tensor, const char * suffix, int bid, int xid);

    std::string str() const;

    operator std::string() const {
        return str();
    }

    friend bool operator==(const std::string & str, const LFG_TN_IMPL & tn) {
        return str == tn.str();
    }

    friend bool operator!=(const std::string & str, const LFG_TN_IMPL & tn) {
        return str != tn.str();
    }
};

struct LFG_TN {
    LFG_TN(lfg_arch_enum arch) : arch(arch) {}

    lfg_arch_enum arch;

    LFG_TN_IMPL operator()(lfg_tensor_enum tensor, const char * suffix, int bid = -1, int xid = -1) const {
        return LFG_TN_IMPL(arch, tensor, suffix, bid, xid);
    }

    LFG_TN_IMPL operator()(lfg_tensor_enum tensor, int bid = -1, int xid = -1) const {
        return LFG_TN_IMPL(arch, tensor, nullptr, bid, xid);
    }
};


